"use client"

import * as React from "react"
import type { JsonSchemaLike } from "lemma-sdk"
import { useSchemaForm } from "lemma-sdk/react"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { Checkbox } from "@/components/ui/checkbox"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { Textarea } from "@/components/ui/textarea"

export interface LemmaSchemaFormProps {
  schema?: JsonSchemaLike | null
  uiSchema?: Record<string, unknown> | null
  initialValues?: Record<string, unknown>
  title?: string
  description?: string
  submitLabel?: string
  disabled?: boolean
  onSubmit?: (data: Record<string, unknown>) => Promise<unknown> | unknown
  onSubmitted?: (data: Record<string, unknown>) => void
}

export function LemmaSchemaForm({
  schema,
  uiSchema,
  initialValues,
  title = "Schema Form",
  description = "Generated from JSON Schema.",
  submitLabel = "Submit",
  disabled = false,
  onSubmit,
  onSubmitted,
}: LemmaSchemaFormProps) {
  const form = useSchemaForm({
    schema,
    uiSchema,
    initialValues,
    onSubmit: async (data) => {
      await onSubmit?.(data)
      onSubmitted?.(data)
    },
  })

  const hasFields = form.fields.length > 0

  const handleSubmit = React.useCallback(async (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault()
    await form.submit()
  }, [form])

  return (
    <Card>
      <CardHeader>
        <CardTitle>{title}</CardTitle>
        <CardDescription>{description}</CardDescription>
      </CardHeader>
      <CardContent>
        <form className="grid gap-4" onSubmit={handleSubmit}>
          {form.error ? (
            <div className="rounded-md border border-[color:var(--resource-danger-border)] bg-[var(--resource-danger-soft)] px-3 py-2 text-sm text-[color:var(--resource-danger)]">
              {form.error.message}
            </div>
          ) : null}

          {!hasFields ? (
            <div className="rounded-md border border-dashed border-[color:var(--resource-border)] bg-[var(--resource-surface-alt)] px-3 py-6 text-sm text-[color:var(--resource-muted)]">
              This schema does not define any editable fields.
            </div>
          ) : null}

          {form.fields.map((field) => {
            const value = form.values[field.name]
            const error = form.fieldErrors[field.name]
            const commonLabel = (
              <div className="grid gap-1.5">
                <Label htmlFor={field.name}>
                  {field.label}
                  {field.required ? " *" : ""}
                </Label>
                {field.description ? (
                  <p className="text-sm text-[color:var(--resource-muted)]">{field.description}</p>
                ) : null}
              </div>
            )

            if (field.kind === "boolean") {
              return (
                <div key={field.name} className="grid gap-2 rounded-lg border border-[color:var(--resource-border)] bg-[var(--resource-surface-alt)] p-3">
                  {commonLabel}
                  <label className="flex items-center gap-3 text-sm">
                    <Checkbox
                      checked={Boolean(value)}
                      onCheckedChange={(checked) => form.setValue(field.name, checked === true)}
                    />
                    <span>{Boolean(value) ? "Enabled" : "Disabled"}</span>
                  </label>
                  {error ? <p className="text-sm text-[color:var(--resource-danger)]">{error}</p> : null}
                </div>
              )
            }

            if (field.kind === "select") {
              return (
                <div key={field.name} className="grid gap-2">
                  {commonLabel}
                  <Select
                    value={typeof value === "string" ? value : ""}
                    onValueChange={(nextValue) => form.setValue(field.name, nextValue)}
                  >
                    <SelectTrigger id={field.name}>
                      <SelectValue placeholder={`Select ${field.label.toLowerCase()}`} />
                    </SelectTrigger>
                    <SelectContent>
                      {field.options.map((option) => (
                        <SelectItem key={option.value} value={option.value}>
                          {option.label}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                  {error ? <p className="text-sm text-[color:var(--resource-danger)]">{error}</p> : null}
                </div>
              )
            }

            if (field.kind === "json" || field.kind === "textarea") {
              return (
                <div key={field.name} className="grid gap-2">
                  {commonLabel}
                  <Textarea
                    id={field.name}
                    rows={field.kind === "json" ? 8 : 4}
                    value={typeof value === "string" ? value : ""}
                    onChange={(event) => form.setValue(field.name, event.target.value)}
                  />
                  {error ? <p className="text-sm text-[color:var(--resource-danger)]">{error}</p> : null}
                </div>
              )
            }

            return (
              <div key={field.name} className="grid gap-2">
                {commonLabel}
                <Input
                  id={field.name}
                  type={
                    field.kind === "number"
                      ? "number"
                      : field.kind === "date"
                        ? "date"
                        : field.kind === "datetime"
                          ? "datetime-local"
                          : field.kind === "email"
                            ? "email"
                            : "text"
                  }
                  value={typeof value === "string" ? value : value ? String(value) : ""}
                  onChange={(event) => form.setValue(field.name, event.target.value)}
                />
                {error ? <p className="text-sm text-[color:var(--resource-danger)]">{error}</p> : null}
              </div>
            )
          })}

          <div className="flex items-center gap-2 pt-2">
            <Button disabled={disabled || form.isSubmitting} type="submit">
              {form.isSubmitting ? "Submitting…" : submitLabel}
            </Button>
            <Button
              disabled={disabled || form.isSubmitting}
              onClick={() => form.reset()}
              type="button"
              variant="outline"
            >
              Reset
            </Button>
          </div>
        </form>
      </CardContent>
    </Card>
  )
}

"use client"

import type { Task } from "lemma-sdk"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"

export interface LemmaAgentOutputCardProps {
  task?: Task | null
  output?: unknown
  finalOnly?: boolean
  title?: string
  description?: string
  emptyText?: string
}

function formatJson(value: unknown): string {
  if (value === null || typeof value === "undefined") return ""
  if (typeof value === "string") return value
  try {
    return JSON.stringify(value, null, 2)
  } catch {
    return String(value)
  }
}

export function LemmaAgentOutputCard({
  task,
  output,
  finalOnly = false,
  title = "Agent Output",
  description = "Inspect the latest structured output from the selected task.",
  emptyText = "Run an agent to inspect output here.",
}: LemmaAgentOutputCardProps) {
  const isFinal = task?.status === "COMPLETED" || task?.status === "FAILED" || task?.status === "CANCELLED" || task?.status === "STOPPED"
  const resolvedOutput = typeof output === "undefined" ? task?.output_data : output
  const visibleOutput = finalOnly && !isFinal ? null : resolvedOutput

  return (
    <Card>
      <CardHeader>
        <CardTitle>{title}</CardTitle>
        <CardDescription>{description}</CardDescription>
      </CardHeader>
      <CardContent className="grid gap-3">
        {task ? (
          <div className="grid gap-2 rounded-md border border-border bg-muted/40 p-3 text-sm">
            <div className="font-medium">Status: {task.status}</div>
            <div className="truncate text-muted-foreground">Task ID: {task.id}</div>
          </div>
        ) : null}
        {visibleOutput ? (
          <pre className="max-h-[420px] overflow-auto rounded-md border border-border bg-muted/40 p-3 text-sm leading-6">
            {formatJson(visibleOutput)}
          </pre>
        ) : (
          <div className="rounded-md border border-dashed border-border bg-muted/30 px-3 py-6 text-sm text-muted-foreground">
            {emptyText}
          </div>
        )}
      </CardContent>
    </Card>
  )
}

"use client"

import type { LemmaClient } from "lemma-sdk"
import { useAgentRun } from "lemma-sdk/react"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"

export interface LemmaAgentMessagesProps {
  client: LemmaClient
  podId?: string
  taskId?: string | null
  title?: string
  description?: string
}

function formatContent(value: unknown): string {
  if (typeof value === "string") return value
  if (value === null || typeof value === "undefined") return ""
  try {
    return JSON.stringify(value, null, 2)
  } catch {
    return String(value)
  }
}

export function LemmaAgentMessages({
  client,
  podId,
  taskId,
  title = "Agent Messages",
  description = "Task messages streamed or loaded from the selected agent run.",
}: LemmaAgentMessagesProps) {
  const run = useAgentRun({
    client,
    podId,
    taskId,
    autoConnect: false,
  })

  return (
    <Card>
      <CardHeader>
        <div className="flex items-start justify-between gap-3">
          <div className="grid gap-1">
            <CardTitle>{title}</CardTitle>
            <CardDescription>{description}</CardDescription>
          </div>
          <Button
            disabled={!taskId}
            onClick={() => {
              void run.loadMessages(taskId)
            }}
            variant="outline"
          >
            Refresh
          </Button>
        </div>
      </CardHeader>
      <CardContent className="grid gap-3">
        {run.error ? (
          <div className="rounded-md border border-destructive/40 bg-destructive/10 px-3 py-2 text-sm text-destructive">
            {run.error.message}
          </div>
        ) : null}
        {!taskId ? (
          <div className="rounded-md border border-dashed border-border bg-muted/30 px-3 py-6 text-sm text-muted-foreground">
            Select or start an agent run to load messages.
          </div>
        ) : run.messages.length === 0 ? (
          <div className="rounded-md border border-dashed border-border bg-muted/30 px-3 py-6 text-sm text-muted-foreground">
            No messages loaded for this run.
          </div>
        ) : (
          run.messages.map((message) => (
            <div key={message.id} className="rounded-md border border-border bg-muted/30 p-3">
              <div className="mb-2 text-xs font-medium uppercase tracking-wide text-muted-foreground">
                {message.role ?? "message"}
              </div>
              <pre className="whitespace-pre-wrap text-sm leading-6">
                {formatContent(message.content)}
              </pre>
            </div>
          ))
        )}
      </CardContent>
    </Card>
  )
}

"use client"

import * as React from "react"
import type { JsonSchemaLike, LemmaClient, Task } from "lemma-sdk"
import { useAgentInputSchema, useAgentRun } from "lemma-sdk/react"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { Label } from "@/components/ui/label"
import { Textarea } from "@/components/ui/textarea"
import { LemmaAgentMessages } from "@/components/lemma/lemma-agent-messages"
import { LemmaAgentOutputCard } from "@/components/lemma/lemma-agent-output-card"
import { LemmaSchemaForm } from "@/components/lemma/lemma-schema-form"

export interface LemmaAgentRunPanelProps {
  client: LemmaClient
  podId?: string
  agentName: string
  inputSchema?: JsonSchemaLike | null
  title?: string
  description?: string
  onStarted?: (task: Task) => void
}

export function LemmaAgentRunPanel({
  client,
  podId,
  agentName,
  inputSchema,
  title = "Agent Runner",
  description = "Start an agent with schema-aware input, then inspect status, output, and messages.",
  onStarted,
}: LemmaAgentRunPanelProps) {
  const [followUp, setFollowUp] = React.useState("")
  const [followUpError, setFollowUpError] = React.useState<string | null>(null)
  const schemaState = useAgentInputSchema({
    client,
    podId,
    agentName,
    enabled: !!agentName && !inputSchema,
  })
  const run = useAgentRun({
    client,
    podId,
    agentName: agentName || undefined,
    autoConnect: true,
    autoConnectOnStart: true,
  })
  const schema = inputSchema ?? schemaState.inputSchema

  return (
    <div className="grid gap-4">
      <Card>
        <CardHeader>
          <CardTitle>{title}</CardTitle>
          <CardDescription>{description}</CardDescription>
        </CardHeader>
        <CardContent className="grid gap-3">
          {schemaState.error ? (
            <div className="rounded-md border border-destructive/40 bg-destructive/10 px-3 py-2 text-sm text-destructive">
              {schemaState.error.message}
            </div>
          ) : null}
          {run.error ? (
            <div className="rounded-md border border-destructive/40 bg-destructive/10 px-3 py-2 text-sm text-destructive">
              {run.error.message}
            </div>
          ) : null}
          <div className="grid gap-2 sm:grid-cols-2">
            <div className="rounded-md border border-border bg-muted/30 p-3 text-sm">
              <div className="text-muted-foreground">Status</div>
              <div className="font-medium">{run.status ?? "idle"}</div>
            </div>
            <div className="rounded-md border border-border bg-muted/30 p-3 text-sm">
              <div className="text-muted-foreground">Task ID</div>
              <div className="truncate font-medium">{run.taskId ?? "none"}</div>
            </div>
          </div>
        </CardContent>
      </Card>

      <LemmaSchemaForm
        disabled={!agentName || run.isStreaming}
        description={schemaState.isLoading ? "Loading agent input schema..." : "Submit structured input to start this agent."}
        onSubmit={async (data) => {
          const task = await run.start(data)
          onStarted?.(task)
        }}
        schema={schema}
        submitLabel={run.isStreaming ? "Running..." : "Run agent"}
        title={agentName ? `Input: ${agentName}` : "Agent Input"}
      />

      {run.isWaitingForInput ? (
        <Card>
          <CardHeader>
            <CardTitle>Follow-up Input</CardTitle>
            <CardDescription>This run is waiting for a response before it can continue.</CardDescription>
          </CardHeader>
          <CardContent className="grid gap-3">
            {followUpError ? (
              <div className="rounded-md border border-destructive/40 bg-destructive/10 px-3 py-2 text-sm text-destructive">
                {followUpError}
              </div>
            ) : null}
            <div className="grid gap-2">
              <Label htmlFor="lemma-agent-follow-up">Response</Label>
              <Textarea
                id="lemma-agent-follow-up"
                onChange={(event) => setFollowUp(event.target.value)}
                rows={4}
                value={followUp}
              />
            </div>
            <Button
              disabled={!followUp.trim()}
              onClick={async () => {
                setFollowUpError(null)
                try {
                  await run.submitInput(followUp)
                  setFollowUp("")
                } catch (error) {
                  setFollowUpError(error instanceof Error ? error.message : "Failed to submit follow-up input.")
                }
              }}
            >
              Submit response
            </Button>
          </CardContent>
        </Card>
      ) : null}

      <LemmaAgentOutputCard task={run.task} />
      <LemmaAgentMessages client={client} podId={podId} taskId={run.taskId} />
    </div>
  )
}

"use client"

import * as React from "react"
import type { Agent, LemmaClient } from "lemma-sdk"
import { Button } from "@/components/ui/button"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { LemmaAgentRunPanel } from "@/components/lemma/lemma-agent-run-panel"

export interface LemmaAgentRunnerPageProps {
  client: LemmaClient
  podId?: string
  agents?: Agent[]
  agentName?: string
  onAgentNameChange?: (agentName: string) => void
  title?: string
  description?: string
}

export function LemmaAgentRunnerPage({
  client,
  podId,
  agents = [],
  agentName,
  onAgentNameChange,
  title = "Agent Runner",
  description = "Choose an agent and run it with a schema-aware input panel.",
}: LemmaAgentRunnerPageProps) {
  const [internalAgentName, setInternalAgentName] = React.useState(agentName ?? agents[0]?.name ?? "")
  const selectedAgentName = agentName ?? internalAgentName

  React.useEffect(() => {
    if (agentName) return
    setInternalAgentName((current) => (
      current && agents.some((agent) => agent.name === current) ? current : (agents[0]?.name ?? "")
    ))
  }, [agentName, agents])

  const setSelectedAgentName = React.useCallback((nextAgentName: string) => {
    if (!agentName) setInternalAgentName(nextAgentName)
    onAgentNameChange?.(nextAgentName)
  }, [agentName, onAgentNameChange])

  return (
    <div className="grid gap-4">
      <Card>
        <CardHeader>
          <CardTitle>{title}</CardTitle>
          <CardDescription>{description}</CardDescription>
        </CardHeader>
        <CardContent className="grid gap-3 sm:grid-cols-[minmax(0,1fr)_auto]">
          <Select value={selectedAgentName} onValueChange={setSelectedAgentName}>
            <SelectTrigger>
              <SelectValue placeholder="Select an agent" />
            </SelectTrigger>
            <SelectContent>
              {agents.map((agent) => (
                <SelectItem key={agent.name} value={agent.name}>
                  {agent.name}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
          <Button
            onClick={() => {
              if (selectedAgentName) setSelectedAgentName(selectedAgentName)
            }}
            variant="outline"
          >
            Use selected agent
          </Button>
        </CardContent>
      </Card>

      {selectedAgentName ? (
        <LemmaAgentRunPanel client={client} podId={podId} agentName={selectedAgentName} />
      ) : (
        <Card>
          <CardHeader>
            <CardTitle>No Agent Selected</CardTitle>
            <CardDescription>Pass agents or an agentName to render the runner.</CardDescription>
          </CardHeader>
        </Card>
      )}
    </div>
  )
}
